import 'chunk_text_decoder.dart';

Stream<String> parseDecodedEventData(Stream<String> textPieces) async* {
  var pending = '';
  await for (final piece in textPieces) {
    pending += piece;
    while (true) {
      final newline = pending.indexOf('\n');
      if (newline < 0) break;
      final line = pending.substring(0, newline);
      pending = pending.substring(newline + 1);
      if (line.startsWith('data:')) {
        yield line.substring(5).trimLeft();
      }
    }
  }
}

Stream<String> parseEventData(Stream<List<int>> bytes) {
  return parseDecodedEventData(decodeByteChunks(bytes));
}

