import 'dart:async';

import '../lib/event_model.dart';
import '../lib/event_parser.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool sameList(List<String> actual, List<String> expected) {
  if (actual.length != expected.length) return false;
  for (var index = 0; index < actual.length; index++) {
    if (actual[index] != expected[index]) return false;
  }
  return true;
}

Future<void> main() async {
  final bytes = Stream<List<int>>.fromIterable([
    'data: first\n'.codeUnits,
    'data: second\n'.codeUnits,
  ]);
  final records = recordsFromData(await parseEventData(bytes).toList());
  check(sameList(records.map((record) => record.data).toList(), ['first', 'second']), 'ordinary records');
  check(records.every((record) => !record.isEmpty), 'record validation');

  final fields = Stream<List<int>>.value('id: 7\ndata: ready\n'.codeUnits);
  check(sameList(await parseEventData(fields).toList(), ['ready']), 'field filtering');
}
